// Field binary yang diharapkan dari web app: 'gambar' (gambar hasil generate yang mau diedit AI)
// Field text: instruksi (perintah edit dalam bahasa natural dari user)
const item = $input.first();
const binari = item.binary || {};
if (!binari.gambar) {
  return [{ json: { sukses: false, error: 'File gambar tidak ditemukan. Pastikan web app upload gambar dengan nama field: gambar', lewatiGemini: true } }];
}
const body = item.json.body || item.json;
const instruksi = (body.instruksi || '').trim();
if (!instruksi) {
  return [{ json: { sukses: false, error: 'Instruksi edit kosong. Isi dulu perintah editnya.', lewatiGemini: true } }];
}
const buffer = await this.helpers.getBinaryDataBuffer(0, 'gambar');
return [{
  json: {
    gambarB64: buffer.toString('base64'),
    gambarMime: binari.gambar.mimeType || 'image/png',
    instruksi
  }
}];

const resp = $input.first().json;

if (resp?.error) {
  return [{ json: { sukses: false, error: 'Gemini API error: ' + JSON.stringify(resp.error) } }];
}

const parts = resp?.candidates?.[0]?.content?.parts || [];
const imgPart = parts.find(p => p.inlineData || p.inline_data);
if (!imgPart) {
  return [{ json: { sukses: false, error: 'AI tidak menghasilkan gambar. Coba ubah instruksi edit.' } }];
}
const d = imgPart.inlineData || imgPart.inline_data;
return [{
  json: {
    sukses: true,
    image: 'data:' + (d.mimeType || d.mime_type || 'image/png') + ';base64,' + d.data
  }
}];
